{n:"2",text:"Find the pointwise limit of \n\n$f_n(x) = x^n$\n\n on $[0,1]$, then determine whether convergence is uniform on $[0,1]$. Check what happens at \n\n$x=1$\n\n separately.",ptype:"ptwise"},
{n:"3",text:"Find the pointwise limit of \n\n$f_n(x) = x^n(1-x)$\n\n on $[0,1]$, then determine whether convergence is uniform. Find the maximum of $f_n$ by differentiation.",ptype:"ptwise"},
{n:"4",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{nx}{1+n^2x^2}$\n\n on $(-\\infty,\\infty)$, then determine whether convergence is uniform.",ptype:"ptwise"},
{n:"5",text:"Find the pointwise limit of \n\n$f_n(x) = n^2 x \\cdot e^{-nx}$\n\n on $[0,\\infty)$, then determine whether convergence is uniform on $[0,\\infty)$.",ptype:"ptwise"},
{n:"6",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{1}{1+nx}$\n\n on $[0,1]$, then determine whether convergence is uniform. Note $f(0)$ is different from $f(x)$ for $x>0$.",ptype:"ptwise"},
{n:"7",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{\\sin(nx)}{n}$\n\n on $(-\\infty,\\infty)$, then determine whether convergence is uniform. Use $|\\sin(nx)| \\leq 1$.",ptype:"unif"},
{n:"8",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{x^2}{x^2+(1-nx)^2}$\n\n on $[0,1]$, then determine whether convergence is uniform.",ptype:"ptwise"},
{n:"9",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{nx}{1+nx}$\n\n on $[0,\\infty)$, then determine whether convergence is uniform on $[0,\\infty)$ and on $[a,\\infty)$ for $a>0$.",ptype:"ptwise"},
{n:"10",text:"Find the pointwise limit of \n\n$f_n(x) = \\cos(x/n)$\n\n on $(-\\infty,\\infty)$, then determine whether convergence is uniform.",ptype:"unif"},
{n:"11",text:"Find the pointwise limit of \n\n$f_n(x) = n \\cdot x \\cdot e^{-nx^2}$\n\n on $(-\\infty,\\infty)$, then determine whether convergence is uniform. Find max of $f_n$ by setting \n\n$f_n'=0$\n\n.",ptype:"ptwise"},
{n:"12",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{\\sin x}{n}$\n\n on $(-\\infty,\\infty)$, then determine whether convergence is uniform.",ptype:"unif"},
{n:"13",text:"Find the pointwise limit of \n\n$f_n(x) = x^{1/n}$\n\n on $[1,\\infty)$, then determine whether convergence is uniform on $[1,\\infty)$.",ptype:"unif"},
{n:"14",text:"Find the pointwise limit of \n\n$f_n(x) = \\frac{x}{n}e^{-x/n}$\n\n on $[0,\\infty)$, then determine whether convergence is uniform.",ptype:"ptwise"},
{n:"15",text:"Find the pointwise limit of \n\n$f_n(x) = \\arctan(nx)$\n\n on $(-\\infty,\\infty)$, then determine whether convergence is uniform. The limit function has a jump discontinuity at \n\n$x=0$\n\n.",ptype:"ptwise"}
